import{_ as t,o,c as a,a4 as i}from"./chunks/framework.BjA-8Gni.js";const h=JSON.parse('{"title":"ADR-008: Layout engine for the UI layer — build cell-native vs adopt Yoga/Taffy","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-008-layout-engine.md","filePath":"reference/decisions/ADR-008-layout-engine.md"}'),n={name:"reference/decisions/ADR-008-layout-engine.md"};function s(r,e,l,d,c,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-008-layout-engine-for-the-ui-layer-—-build-cell-native-vs-adopt-yoga-taffy" tabindex="-1">ADR-008: Layout engine for the UI layer — build cell-native vs adopt Yoga/Taffy <a class="header-anchor" href="#adr-008-layout-engine-for-the-ui-layer-—-build-cell-native-vs-adopt-yoga-taffy" aria-label="Permalink to &quot;ADR-008: Layout engine for the UI layer — build cell-native vs adopt Yoga/Taffy&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: ✅ Accepted — 2026-06-28 <strong>Source</strong>: Design discussion, settled when the <code>@jsvision/ui</code> scaffold landed</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The foundation (<code>@jsvision/core</code>) does <strong>no layout</strong> — widgets/apps address cells by <code>(x, y)</code> and hand-draw into a <code>ScreenBuffer</code> (see the keyboard/mouse playground demo). The upcoming UI/widget layer needs <em>some</em> layout system: nesting, resizing, and dynamic content make absolute coordinates untenable.</p><p>The question on the table: <strong>do we adopt a layout library (Yoga, or something else) for a flexbox-ish / flex-grid-ish engine, or build our own?</strong> This was explicitly discussed <em>setting aside</em> the native-compilation concern — i.e., on technical merit, not packaging.</p><h2 id="the-decisive-technical-factor-cells-are-integers-layout-engines-think-in-floats" tabindex="-1">The decisive technical factor: cells are integers, layout engines think in floats <a class="header-anchor" href="#the-decisive-technical-factor-cells-are-integers-layout-engines-think-in-floats" aria-label="Permalink to &quot;The decisive technical factor: cells are integers, layout engines think in floats&quot;">​</a></h2><p>Yoga and essentially every web layout engine compute in <strong>floating-point pixels</strong>. On a screen a sub-pixel error is invisible; in a terminal <strong>every box must land on an integer column/row</strong>. Rounding each flex child independently makes the children&#39;s widths not sum to the container width → <strong>1-cell gaps or overlaps at flex boundaries</strong>. Ink (which uses Yoga) exhibits exactly this class of off-by-one quirk.</p><p>The correct fix is <strong>integer apportionment</strong>: distribute leftover cells one at a time to the children with the largest fractional remainders (largest-remainder / Hamilton method) so a row/column fills <em>exactly</em> to the edge, every time. A cell-native engine does this by construction. Yoga can be coerced toward integers (<code>pointScaleFactor=1</code>), but that rounds a float result after the fact rather than apportioning — papering over a model mismatch. <strong>This argument holds even if Yoga shipped as one clean binary.</strong></p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Model</th><th>Runtime</th><th>Grid?</th><th>Cell-integer fit</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Build cell-native (pure TS)</strong></td><td>flex subset (+ grid/dock later)</td><td>zero dep</td><td>yes, if added</td><td><strong>native — apportion in cells</strong></td><td>~few hundred LOC; tunable; paradigm-fit; we maintain it</td></tr><tr><td><strong>Yoga</strong> (<code>yoga-layout</code>)</td><td>flexbox only</td><td>WASM (no node-gyp anymore)</td><td>❌ no grid</td><td>float→round (gaps)</td><td>Battle-tested (React Native, Ink); black box; can&#39;t tune rounding</td></tr><tr><td><strong>Taffy</strong></td><td>flexbox <strong>+ CSS grid</strong></td><td>Rust→WASM</td><td>✅ yes</td><td>float→round</td><td>Modern, maintained (Bevy/Dioxus); strongest &quot;buy&quot; option if grid is needed</td></tr><tr><td><strong>kiwi.js</strong> (Cassowary)</td><td>linear constraints</td><td>pure JS</td><td>via constraints</td><td>float→round</td><td>Very expressive (Ratatui-style); different mental model; heavier API</td></tr></tbody></table><h3 id="what-reference-tui-frameworks-actually-chose-no-consensus-on-flexbox" tabindex="-1">What reference TUI frameworks actually chose (no consensus on flexbox) <a class="header-anchor" href="#what-reference-tui-frameworks-actually-chose-no-consensus-on-flexbox" aria-label="Permalink to &quot;What reference TUI frameworks actually chose (no consensus on flexbox)&quot;">​</a></h3><ul><li><strong>Ink</strong> (JS) → Yoga / flexbox. Proves it is <em>viable</em>, cell-rounding warts and all.</li><li><strong>Textual</strong> (Python) → <strong>its own engine</strong>, CSS-like with grid + dock + fractional <code>fr</code> units. Widely loved; deliberately not flexbox-via-a-C-lib.</li><li><strong>Ratatui</strong> (Rust) → a <strong>constraint solver</strong> (Cassowary), not flexbox.</li><li><strong>Turbo Vision</strong> (the SDK&#39;s namesake) → <strong>rect + edge-anchoring</strong> (<code>growMode</code>); no flow layout at all.</li></ul><p>The field splits into <em>borrow-Yoga</em> (Ink) vs <em>build-for-the-medium</em> (Textual, Ratatui) — and the most-praised modern TUIs are in the build camp.</p><h3 id="flexbox-ish-vs-flexgrid-ish-are-different-decisions" tabindex="-1">flexbox-ish vs flexgrid-ish are different decisions <a class="header-anchor" href="#flexbox-ish-vs-flexgrid-ish-are-different-decisions" aria-label="Permalink to &quot;flexbox-ish vs flexgrid-ish are different decisions&quot;">​</a></h3><ul><li><strong>Flexbox</strong> (1-D row/column, grow/shrink/basis, justify/align) covers toolbars, lists, side-by-side panels, responsive stacking — ~80% of TUI layout.</li><li><strong>Grid / flexgrid</strong> (2-D tracks: fixed / <code>fr</code> / auto) is what dashboards, tables, and form layouts want. <strong>Yoga does not do grid; Taffy does.</strong> Grid is actually <em>easier</em> to make integer-correct than flexbox (same largest-remainder trick). If grid is a real requirement, that alone rules Yoga out.</li><li>A strong toolkit usually offers <strong>flex + grid + dock/anchor</strong> (Textual&#39;s model), because different screens want different tools — &quot;a layout library&quot; ≠ &quot;just flexbox&quot;.</li></ul><h2 id="decision-accepted" tabindex="-1">Decision (Accepted) <a class="header-anchor" href="#decision-accepted" aria-label="Permalink to &quot;Decision (Accepted)&quot;">​</a></h2><p><strong>Build a small cell-native layout engine in pure TypeScript</strong> — not Yoga/Taffy. Confirmed 2026-06-28. The build-vs-buy call rests on two independent arguments that both point the same way: integer-cell correctness <em>by construction</em> (apportionment, not float-rounding), and keeping the zero-dep, pure-JS, auditable identity that <code>check:deps</code> enforces (Yoga is WASM, Taffy is Rust→WASM).</p><p>Confirmed scope and shape:</p><ol><li><strong>Flex first, grid later.</strong> Phase 1 is 1-D flex — <code>row</code>/<code>col</code> with grow/shrink/basis, justify/align, gap/pad. That covers the app shell (menubar/desktop/statusline as a flex column) and ~80% of widgets (scrollbars, dialog forms). 2-D <strong>grid</strong> (fixed/<code>fr</code>/auto tracks, for tables + dashboards) is <strong>Tier 2</strong>, added behind the same interface. Edge-docking (TV <code>growMode</code>) is expressible via flex justify/align — no separate dock primitive until a real need appears.</li><li><strong>Lives as a module inside <code>@jsvision/ui</code></strong> (<code>src/layout/</code>), not a separate package, behind the pure-function seam below. Extract to a standalone <code>@jsvision/layout</code> package later only if independent reuse/versioning is ever actually needed.</li></ol><p>Two guardrails keep &quot;build&quot; low-risk:</p><ol><li><strong>Clean seam</strong> — layout is a pure function <code>(box tree, {cols, rows}) → integer rects</code>; the renderer just paints into those rects. Small, golden-testable surface (the project&#39;s sweet spot), zero new deps.</li><li><strong>Low lock-in</strong> — start flex-only; if a future need outgrows it, swap in <strong>Taffy</strong> (flex + grid) behind the same interface without touching widgets.</li></ol><p><strong>Flip to &quot;buy&quot; (Taffy) only if</strong> full CSS-spec fidelity is ever needed <em>fast</em> and we don&#39;t want to own/maintain the engine.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Integer-cell correctness by construction (no Yoga-style boundary gaps).</li><li>Keeps the zero-dep, auditable, pure-TS identity; blends flex + grid + TV anchoring.</li><li>A small, testable module behind a stable rect interface.</li></ul><h3 id="negative-risks" tabindex="-1">Negative / Risks <a class="header-anchor" href="#negative-risks" aria-label="Permalink to &quot;Negative / Risks&quot;">​</a></h3><ul><li>We build and maintain it; not full CSS-flexbox spec fidelity (wrap, min/max, aspect-ratio, baseline align take real effort).</li><li>Risk of scope creep toward &quot;reimplement CSS&quot; — mitigated by shipping a deliberate <em>subset</em> and a clean swap-to-Taffy escape hatch.</li></ul><h2 id="resolved-questions-implementation-notes" tabindex="-1">Resolved questions &amp; implementation notes <a class="header-anchor" href="#resolved-questions-implementation-notes" aria-label="Permalink to &quot;Resolved questions &amp; implementation notes&quot;">​</a></h2><ul><li><strong>Model</strong> — flex subset first (<code>row</code>/<code>col</code>, grow/shrink/basis, justify/align, gap/pad); grid is Tier 2; no standalone dock primitive initially. <em>(Resolved 2026-06-28.)</em></li><li><strong>Location</strong> — a module inside <code>@jsvision/ui</code> (<code>src/layout/</code>), consuming <code>@jsvision/core</code> geometry; extractable to <code>@jsvision/layout</code> later. <em>(Resolved 2026-06-28.)</em></li><li><strong>Full flexbox spec fidelity</strong> (wrap, min/max, aspect-ratio, baseline) is <strong>not</strong> a goal; ship a deliberate subset. Revisit Taffy only if that ever changes.</li><li><strong>First build step (de-risking spike)</strong> — the integer flex-distribution (apportionment) core: ~40 LOC + a golden test asserting a row of <code>fr</code> children fills <em>exactly</em> to the container edge with no gap/overlap. Validates the cell-native premise before building out the full module.</li><li><strong>API flavour</strong> (CSS-flexbox-subset vs Textual-style <code>fr</code>/<code>auto</code> sizing) is an implementation detail for <code>make_requirements</code>/<code>make_plan</code>, not this ADR.</li></ul>',29)])])}const f=t(n,[["render",s]]);export{h as __pageData,f as default};
